template<typename T>
class MyContainer {
public:
    void add(const T& item);
    T get(size_t index) const;
private:
    std::vector<T> data;
};

template<typename T>
void MyContainer<T>::add(const T& item) {
    data.push_back(item);
}

template<typename T>
T MyContainer<T>::get(size_t index) const {
    return data.at(index);
}
